1	//! Stream-aware output framing around opaque theory payloads.
2	//!
3	//! A batch run writes to two independent streams (see `workspace/BEHAVIOR.md`
4	//! §10). This module models which text lands on which stream and assembles both
5	//! byte-exactly. The theory pretty-print (`theory <name> … end`, including any
6	//! `WARNING:` block and the `Generated from:` comment) is an opaque payload slot;
7	//! everything around it — the maude preamble, the per-theory progress markers, and
8	//! the "summary of summaries" block — is built here.
9	//!
10	//! Stream assignment: the maude preamble and progress markers go to stderr;
11	//! payloads and the summary block go to stdout.
12	
13	use crate::stream::Streams;
14	use crate::version::{maude_preamble, MaudeInfo};
15	
16	/// Width of the `=` rule that brackets the summary block (observed: 78).
17	const RULE_WIDTH: usize = 78;
18	
19	/// Per-theory progress phases, in the order printed for a fully closed theory.
20	#[derive(Debug, Clone, Copy)]
21	pub enum Phase {
22	    Loaded,
23	    Translated,
24	    DerivationChecksStarted,
25	    DerivationChecksEnded,
26	    Closed,
27	}
28	
29	impl Phase {
30	    fn text(self) -> &'static str {
31	        match self {
32	            Phase::Loaded => "Theory loaded",
33	            Phase::Translated => "Theory translated",
34	            Phase::DerivationChecksStarted => "Derivation checks started",
35	            Phase::DerivationChecksEnded => "Derivation checks ended",
36	            Phase::Closed => "Theory closed",
37	        }
38	    }
39	}
40	
41	/// The five progress phases a closed theory reports.
42	pub const CLOSED_PHASES: [Phase; 5] = [
43	    Phase::Loaded,
44	    Phase::Translated,
45	    Phase::DerivationChecksStarted,
46	    Phase::DerivationChecksEnded,
47	    Phase::Closed,
48	];
49	
50	/// One progress line: `[Theory <name>] <phase>\n` (stderr).
51	pub fn progress_line(theory: &str, phase: Phase) -> String {
52	    format!("[Theory {}] {}\n", theory, phase.text())
53	}
54	
55	fn progress_block(theory: &str, phases: &[Phase]) -> String {
56	    phases.iter().map(|p| progress_line(theory, *p)).collect()
57	}
58	
59	/// Whether a lemma quantifies over all traces or asserts an existing trace.
60	#[derive(Debug, Clone, Copy)]
61	pub enum TraceKind {
62	    AllTraces,
63	    ExistsTrace,
64	}
65	
66	impl TraceKind {
67	    fn text(self) -> &'static str {
68	        match self {
69	            TraceKind::AllTraces => "all-traces",
70	            TraceKind::ExistsTrace => "exists-trace",
71	        }
72	    }
73	}
74	
75	/// Per-lemma verdict. The printed text of a falsified verdict depends on the
76	/// lemma's [`TraceKind`] (see [`verdict_phrase`]); the verified, incomplete, and
77	/// cannot-be-finished verdicts print the same for both kinds.
78	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
79	pub enum LemmaResult {
80	    /// The proof closed: `verified`.
81	    Verified,
82	    /// A trace was found (all-traces) / no trace exists (exists-trace); the
83	    /// printed phrase is kind-dependent (see [`verdict_phrase`]).
84	    Falsified,
85	    /// The proof was not driven to a terminal state — a lemma not selected for
86	    /// proving, a `--prove`/`--lemma` pattern that matched nothing, or a proof cut
87	    /// short by `--bound`: `analysis incomplete`. The `(<N> steps)` count is the
88	    /// explored depth, and a bounded cutoff adds no other marker.
89	    AnalysisIncomplete,
90	    /// The proof reached a terminal `UNFINISHABLE` step and could not continue:
91	    /// `analysis cannot be finished (reducible operators in subterms)`. Observed
92	    /// only for reducible operators appearing inside subterm goals; renders
93	    /// uniformly for both trace-kinds (no falsified-style suffix) and composes with
94	    /// the `--diff` side prefixes exactly like any other verdict. Distinct from
95	    /// [`AnalysisIncomplete`](Self::AnalysisIncomplete): a `--bound` cutoff of the
96	    /// same lemma prints `analysis incomplete`, not this phrase.
97	    AnalysisCannotBeFinished,
98	}
99	
100	/// Which system a summary line describes. A non-diff run reports every lemma as
101	/// [`LemmaSide::Whole`] (no prefix). Under `--diff` the prover verifies each
102	/// ordinary lemma separately against the two projected systems, prefixing its
103	/// line with `RHS`/`LHS`, and reports the auto-generated observational-equivalence
104	/// lemma as a [`LemmaSide::Diff`] line (`DiffLemma:` prefix, no trace-kind). In a
105	/// diff summary the entries appear in the order: for each ordinary lemma its
106	/// `RHS` line then its `LHS` line, and finally the single `Diff` line.
107	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
108	pub enum LemmaSide {
109	    Whole,
110	    Rhs,
111	    Lhs,
112	    Diff,
113	}
114	
115	/// The verdict phrase for a `<result>` under a given [`TraceKind`]. `verified`,
116	/// `analysis incomplete`, and `analysis cannot be finished (reducible operators in
117	/// subterms)` read the same for both kinds; a `falsified` verdict carries a
118	/// kind-dependent suffix: `- found trace` for an all-traces lemma (a
119	/// counter-example trace was produced) and `- no trace found` for an exists-trace
120	/// lemma (no witnessing trace exists).
121	fn verdict_phrase(result: LemmaResult, kind: TraceKind) -> &'static str {
122	    match result {
123	        LemmaResult::Verified => "verified",
124	        LemmaResult::AnalysisIncomplete => "analysis incomplete",
125	        LemmaResult::AnalysisCannotBeFinished => {
126	            "analysis cannot be finished (reducible operators in subterms)"
127	        }
128	        LemmaResult::Falsified => match kind {
129	            TraceKind::AllTraces => "falsified - found trace",
130	            TraceKind::ExistsTrace => "falsified - no trace found",
131	        },
132	    }
133	}
134	
135	/// One lemma's verdict line in a theory's summary body. In a non-diff run this is
136	/// `<name> (<kind>): <verdict> (<steps> steps)`; under `--diff` a projected
137	/// ordinary lemma prefixes that with `RHS :  `/`LHS :  `, and the
138	/// observational-equivalence lemma renders as
139	/// `DiffLemma:  <name> : <verdict> (<steps> steps)` (no trace-kind).
140	#[derive(Debug, Clone)]
141	pub struct LemmaOutcome {
142	    pub name: String,
143	    /// The lemma's trace quantification. Ignored when [`side`](Self::side) is
144	    /// [`LemmaSide::Diff`]: an observational-equivalence lemma has no trace-kind,
145	    /// and its `falsified` verdict always reads `- found trace`.
146	    pub kind: TraceKind,
147	    pub result: LemmaResult,
148	    /// The `<N>` in `(<N> steps)` — the number of proof steps explored (also the
149	    /// value shown for bounded/incomplete analyses, reflecting the explored depth).
150	    pub steps: u64,
151	    /// Which projected system this line reports (see [`LemmaSide`]).
152	    pub side: LemmaSide,
153	}
154	
155	impl LemmaOutcome {
156	    /// A non-diff lemma line (`<name> (<kind>): <verdict> (<N> steps)`).
157	    pub fn whole(
158	        name: impl Into<String>,
159	        kind: TraceKind,
160	        result: LemmaResult,
161	        steps: u64,
162	    ) -> Self {
163	        LemmaOutcome { name: name.into(), kind, result, steps, side: LemmaSide::Whole }
164	    }
165	
166	    /// A `--diff` projected ordinary-lemma line for one side ([`LemmaSide::Rhs`]
167	    /// or [`LemmaSide::Lhs`]).
168	    pub fn projected(
169	        side: LemmaSide,
170	        name: impl Into<String>,
171	        kind: TraceKind,
172	        result: LemmaResult,
173	        steps: u64,
174	    ) -> Self {
175	        LemmaOutcome { name: name.into(), kind, result, steps, side }
176	    }
177	
178	    /// A `--diff` observational-equivalence line
179	    /// (`DiffLemma:  <name> : <verdict> (<N> steps)`).
180	    pub fn diff_lemma(name: impl Into<String>, result: LemmaResult, steps: u64) -> Self {
181	        LemmaOutcome {
182	            name: name.into(),
183	            kind: TraceKind::AllTraces,
184	            result,
185	            steps,
186	            side: LemmaSide::Diff,
187	        }
188	    }
189	
190	    /// The single result line, without its `  ` body indent.
191	    fn line(&self) -> String {
192	        match self.side {
193	            LemmaSide::Diff => format!(
194	                "DiffLemma:  {} : {} ({} steps)",
195	                self.name,
196	                verdict_phrase(self.result, TraceKind::AllTraces),
197	                self.steps
198	            ),
199	            LemmaSide::Whole | LemmaSide::Rhs | LemmaSide::Lhs => {
200	                let core = format!(
201	                    "{} ({}): {} ({} steps)",
202	                    self.name,
203	                    self.kind.text(),
204	                    verdict_phrase(self.result, self.kind),
205	                    self.steps
206	                );
207	                match self.side {
208	                    LemmaSide::Rhs => format!("RHS :  {core}"),
209	                    LemmaSide::Lhs => format!("LHS :  {core}"),
210	                    _ => core,
211	                }
212	            }
213	        }
214	    }
215	}
216	
217	/// Prefix shared by the `WARNING:` line and its aligned advisory continuation.
218	const WARNING_PREFIX: &str = "  WARNING: ";
219	
220	/// The wellformedness-warning heading of a theory's summary body. Present only
221	/// when at least one wellformedness check failed.
222	#[derive(Debug, Clone)]
223	pub struct WarningSummary {
224	    /// The `<N>` in `WARNING: <N> wellformedness check failed!` (the noun stays
225	    /// singular "check" regardless of `<N>`).
226	    pub failed_checks: u64,
227	    /// Whether the advisory line `The analysis results might be wrong!` follows
228	    /// the count line. Observed: emitted exactly when the run is a proving run
229	    /// (`--prove`), independent of how many lemmas were actually proved (a
230	    /// proving run with zero matched lemmas still emits it; a plain analyze run
231	    /// never does).
232	    pub analysis_maybe_wrong: bool,
233	}
234	
235	impl WarningSummary {
236	    /// The warning heading (one or two lines, each `\n`-terminated). The advisory
237	    /// continuation is left-padded to align under the text after `WARNING: `.
238	    fn render(&self) -> String {
239	        let mut s = String::new();
240	        s.push_str(WARNING_PREFIX);
241	        s.push_str(&format!("{} wellformedness check failed!\n", self.failed_checks));
242	        if self.analysis_maybe_wrong {
243	            for _ in 0..WARNING_PREFIX.len() {
244	                s.push(' ');
245	            }
246	            s.push_str("The analysis results might be wrong!\n");
247	        }
248	        s
249	    }
250	}
251	
252	/// One theory's contribution to the "summary of summaries" block.
253	#[derive(Debug, Clone)]
254	pub struct Summary {
255	    /// The `analyzed:` path, echoed exactly as given on the command line.
256	    pub analyzed: String,
257	    /// The `output:` path, present only when the theory was written to a file
258	    /// (`-o`/`-O`).
259	    pub output: Option<String>,
260	    /// Rendered as seconds with two decimals (e.g. `0.39s`).
261	    pub processing_time: f64,
262	    /// The wellformedness-warning heading, when any check failed.
263	    pub warnings: Option<WarningSummary>,
264	    /// The per-lemma verdict lines, in report order.
265	    pub lemmas: Vec<LemmaOutcome>,
266	}
267	
268	impl Summary {
269	    /// The theory's block: the `analyzed:` header, a blank line, the aligned
270	    /// key/value rows (`output:` when present, then `processing time:`), then the
271	    /// body. The body opens with a `  ` (two-space) line and carries up to two
272	    /// sections — the warning heading and the lemma lines, in that order — each
273	    /// section preceded by a `  ` line (so a `  ` line also separates the two when
274	    /// both are present).
275	    fn render_block(&self) -> String {
276	        let mut b = String::new();
277	        b.push_str(&format!("analyzed: {}\n", self.analyzed));
278	        b.push('\n');
279	
280	        // Aligned key/value rows: labels right-padded to the widest label, then a
281	        // single space, so every value starts at the same column.
282	        let mut rows: Vec<(&str, String)> = Vec::new();
283	        if let Some(o) = &self.output {
284	            rows.push(("output:", o.clone()));
285	        }
286	        rows.push(("processing time:", format!("{:.2}s", self.processing_time)));
287	        let width = rows.iter().map(|(label, _)| label.len()).max().unwrap_or(0);
288	        for (label, value) in &rows {
289	            b.push_str("  ");
290	            b.push_str(label);
291	            for _ in 0..(width - label.len()) {
292	                b.push(' ');
293	            }
294	            b.push(' ');
295	            b.push_str(value);
296	            b.push('\n');
297	        }
298	
299	        // Body: an opening `  ` (two-space) line, then the present sections joined
300	        // by another `  ` line — the warning heading first, then the lemma lines.
301	        b.push_str("  \n");
302	        let mut sections: Vec<String> = Vec::new();
303	        if let Some(w) = &self.warnings {
304	            sections.push(w.render());
305	        }
306	        if !self.lemmas.is_empty() {
307	            let mut lines = String::new();
308	            for l in &self.lemmas {
309	                lines.push_str("  ");
310	                lines.push_str(&l.line());
311	                lines.push('\n');
312	            }
313	            sections.push(lines);
314	        }
315	        b.push_str(&sections.join("  \n"));
316	        b
317	    }
318	}
319	
320	/// The full "summary of summaries" section as it appears on stdout: a leading
321	/// blank line (the payload/summary separator, always present), the top `=` rule,
322	/// the header, each theory block preceded by a blank line, a trailing blank line,
323	/// and the bottom rule.
324	pub fn render_summary(summaries: &[Summary]) -> String {
325	    let rule = "=".repeat(RULE_WIDTH);
326	    let mut out = String::new();
327	    out.push('\n');
328	    out.push_str(&rule);
329	    out.push('\n');
330	    out.push_str("summary of summaries:\n");
331	    for s in summaries {
332	        out.push('\n');
333	        out.push_str(&s.render_block());
334	    }
335	    out.push('\n');
336	    out.push_str(&rule);
337	    out.push('\n');
338	    out
339	}
340	
341	/// A theory processed by a closed batch run.
342	#[derive(Debug, Clone)]
343	pub struct BatchTheory {
344	    /// Name used in the `[Theory <name>]` progress markers (stderr).
345	    pub name: String,
346	    /// The printed theory payload (stdout), or `None` when it was written to an
347	    /// output file instead.
348	    pub payload: Option<String>,
349	    /// Further progress lines the engine emitted for this theory after the five
350	    /// closed phases (stderr), verbatim and newline-terminated. Empty for a plain
351	    /// analyze run; under `--prove` it carries the `[Saturating Sources] …` lines.
352	    pub extra_progress: String,
353	    /// This theory's summary contribution (stdout).
354	    pub summary: Summary,
355	}
356	
357	/// A closed batch run over one or more theories.
358	///
359	/// stderr: the maude preamble, then per theory the five progress markers followed
360	/// by any extra engine progress. stdout: the printed payloads (in order), then one
361	/// combined summary block.
362	pub fn frame_batch(maude: &MaudeInfo, theories: &[BatchTheory]) -> Streams {
363	    let mut s = Streams::default();
364	    s.err.push_str(&maude_preamble(maude));
365	    for t in theories {
366	        s.err.push_str(&progress_block(&t.name, &CLOSED_PHASES));
367	        s.err.push_str(&t.extra_progress);
368	    }
369	    for t in theories {
370	        if let Some(p) = &t.payload {
371	            s.out.push_str(p);
372	        }
373	    }
374	    let summaries: Vec<Summary> = theories.iter().map(|t| t.summary.clone()).collect();
375	    s.out.push_str(&render_summary(&summaries));
376	    s
377	}
378	
379	/// A theory under `--parse-only`: its name (for the single progress marker) and
380	/// its opaque payload.
381	#[derive(Debug, Clone)]
382	pub struct LoadedTheory {
383	    pub name: String,
384	    pub payload: String,
385	}
386	
387	/// A `--parse-only` run: stderr carries one `Theory loaded` marker per theory (no
388	/// preamble); stdout carries the concatenated payloads (no summary block).
389	pub fn frame_parse_only(theories: &[LoadedTheory]) -> Streams {
390	    let mut s = Streams::default();
391	    for t in theories {
392	        s.err.push_str(&progress_line(&t.name, Phase::Loaded));
393	        s.out.push_str(&t.payload);
394	    }
395	    s
396	}
397	
398	/// A `variants` run: stdout carries the variant payload; stderr carries only the
399	/// maude preamble (no progress markers, no summary).
400	pub fn frame_variants(maude: &MaudeInfo, payload: &str) -> Streams {
401	    Streams { out: payload.to_string(), err: maude_preamble(maude) }
402	}
