344	/// Extract each theory block's dynamic slots `(analyzed, output, time)` from a
345	/// summary section, so the framing tests are robust to path/timing variation.
346	fn slots(section: &str) -> Vec<(String, Option<String>, f64)> {
347	    let mut out: Vec<(String, Option<String>, f64)> = Vec::new();
348	    let mut cur: Option<(String, Option<String>, f64)> = None;
349	    for line in section.lines() {
350	        if let Some(a) = line.strip_prefix("analyzed: ") {
351	            if let Some(c) = cur.take() {
352	                out.push(c);
353	            }
354	            cur = Some((a.to_string(), None, 0.0));
355	        } else if let Some(o) = line.strip_prefix("  output:") {
356	            if let Some(c) = cur.as_mut() {
357	                c.1 = Some(o.trim_start().to_string());
358	            }
359	        } else if let Some(t) = line.strip_prefix("  processing time: ") {
360	            if let Some(c) = cur.as_mut() {
361	                c.2 = t.trim_end_matches('s').parse().expect("time");
362	            }
363	        }
364	    }
365	    if let Some(c) = cur.take() {
366	        out.push(c);
367	    }
368	    out
369	}
