556	// ---- GAP 1 (Round 5): summary content — warnings + lemmas, verdicts, bounded ---
557	
558	/// Frame a single closed theory from its captured `.out`/`.err` fixture: slice the
559	/// opaque payload and summary slots out of stdout, recover the theory's
560	/// `extra_progress` (anything after its `Theory closed` marker) from stderr, and
561	/// reassemble both streams with the given summary content.
562	fn frame_single(
563	    out_cap: &str,
564	    err_cap: &str,
565	    name: &str,
566	    warnings: Option<WarningSummary>,
567	    lemmas: Vec<LemmaOutcome>,
568	) -> Streams {
569	    let cut = summary_start(out_cap);
570	    let (analyzed, output, time) = slots(&out_cap[cut..]).remove(0);
571	    let marker = format!("[Theory {name}] Theory closed\n");
572	    let closed_end = err_cap.find(&marker).expect("closed marker") + marker.len();
573	    let theory = BatchTheory {
574	        name: s(name),
575	        payload: Some(out_cap[..cut].to_string()),
576	        extra_progress: err_cap[closed_end..].to_string(),
577	        summary: Summary { analyzed, output, processing_time: time, warnings, lemmas },
578	    };
579	    frame_batch(&MaudeInfo::default(), &[theory])
580	}
