912	    // The emitter, driven by hand event-by-event (as a real consumer would while
913	    // the prover runs), yields the same per-stream bytes as frame_batch. This is
914	    // the "consumer chooses flush timing" surface — the collector is one Sink;
915	    // ordering and content are the emitter's contract.
916	    let theory = BatchTheory {
917	        name: s("NSLPK3"),
918	        payload: Some(s("theory NSLPK3\n..payload..\nend\n")),
919	        extra_progress: s("[Saturating Sources] Step 1 (Max 5)\n[Saturating Sources] Done\n"),
920	        summary: Summary {
