926	        },
927	    };
928	    let mut sink = StreamCollector::default();
929	    {
930	        let mut e = BatchEmitter::begin(&mut sink, &MaudeInfo::default());
931	        e.closed_phases("NSLPK3");
932	        e.extra_progress("[Saturating Sources] Step 1 (Max 5)\n[Saturating Sources] Done\n");
933	        e.payload(Some("theory NSLPK3\n..payload..\nend\n"));
934	        e.record_summary(theory.summary.clone());
935	        e.finish();
936	    }
937	    let assembled = frame_batch(&MaudeInfo::default(), std::slice::from_ref(&theory));
938	    assert_eq!(sink.streams.out, assembled.out);
