1017	/// Build a single-theory summary from a `--diff` capture's dynamic slots and
1018	/// assert `render_summary` reproduces that capture's summary section byte-exactly.
1019	fn assert_diff_summary(out_cap: &str, warnings: Option<WarningSummary>, lemmas: Vec<LemmaOutcome>) {
1020	    let section = &out_cap[summary_start(out_cap)..];
1021	    let (analyzed, output, time) = slots(section).remove(0);
1022	    let summary = Summary { analyzed, output, processing_time: time, warnings, lemmas };
1023	    assert_eq!(render_summary(std::slice::from_ref(&summary)), section);
1024	}
