//! Byte-parity tests for the vendored clean-room console text surface
//! (`cli::{args,errors,framing,help,modes,parse,stream,version}`).
//!
//! Ported verbatim (import paths + fixture directory adapted) from the clean
//! crate's own `tests/cli_tests.rs`. Fixtures in `tests/console_fixtures/` are
//! raw captures of the black-box HS binary; the `split_*` captures were taken
//! with stdout and stderr redirected separately (`1>out 2>err`), so the framing
//! tests reassemble BOTH streams and compare them byte-for-byte. This is the
//! automated form of the console cluster's split-stream-captures gate: it proves
//! the vendored modules reproduce the reference output exactly.

use tamarin_prover::cli::args::{parse_args, read_haskell_int, Args, OutputModule, Parsed, PartialEval, StopOnTrace};
use tamarin_prover::cli::emit::{drive_batch, BatchEmitter, StreamCollector};
use tamarin_prover::cli::errors::{app_error, open_file_error, OpenFileError, ParseError};
use tamarin_prover::cli::framing::{
    frame_batch, frame_parse_only, frame_variants, render_summary, BatchTheory, LemmaOutcome,
    LemmaResult, LemmaSide, LoadedTheory, Summary, TraceKind, WarningSummary,
};
use tamarin_prover::cli::stream::{Stream, Streams};
use tamarin_prover::cli::version::{frame_version, render_version, MaudeInfo, VersionInfo};
use tamarin_prover::cli::help::render_help;
use tamarin_prover::cli::modes::Mode;
use tamarin_prover::cli::parse::{parse, Command};

fn s(a: &str) -> String {
    a.to_string()
}
fn argv(items: &[&str]) -> Vec<String> {
    items.iter().map(|x| x.to_string()).collect()
}
fn run_err(items: &[&str]) -> ParseError {
    parse_args(&argv(items)).unwrap_err()
}
fn run_ok(items: &[&str]) -> Args {
    match parse_args(&argv(items)).unwrap() {
        Parsed::Run(a) => a,
        other => panic!("expected Run, got {other:?}"),
    }
}

// ---- help ---------------------------------------------------------------------

#[test]
fn help_pages_are_byte_exact() {
    assert_eq!(render_help(Mode::Batch), include_str!("console_fixtures/help_global.txt"));
    assert_eq!(render_help(Mode::Interactive), include_str!("console_fixtures/help_interactive.txt"));
    assert_eq!(render_help(Mode::Variants), include_str!("console_fixtures/help_variants.txt"));
    assert_eq!(render_help(Mode::Test), include_str!("console_fixtures/help_test.txt"));
}

