562	fn run_batch(args: &Args) -> Result<i32, RunError> {
563	    // HS-faithful internal parallelism via rayon.  Mirrors the four
564	    // `using parList`/`parTraversable`/`parMap` sites HS uses (see
565	    // `lib/theory/src/Prover.hs:102,195`, `Theory/Constraint/Solver/Sources.hs`,
566	    // `lib/theory/src/TheoryObject.hs:744,752`).  Default: full machine
567	    // parallelism (`available_parallelism()`, uncapped — Maude IPC runs
568	    // through the contention-free `MaudePool`, so larger pools scale;
569	    // memory is budgeted via `--maude-processes`).
570	    // `--processors=1` falls back to a 1-thread pool, guaranteeing
571	    // byte-identical output to the pre-parallel sequential path.
572	    init_rayon_pool(args);
573	    if args.diff {
574	        return Err(RunError(
575	            "--diff (observational equivalence) is not yet ported to the Rust prover."
576	                .to_string(),
577	        ));
578	    }
579	    if args.output_module.is_some() {
580	        return Err(RunError(
581	            "--output-module is not yet ported to the Rust prover.".to_string(),
582	        ));
583	    }
584	    // `--stop-on-trace` selects HS's `SolutionExtractor` (Theory/Proof.hs:695,
585	    // TheoryLoader.hs:355-362) and, when the CLI flag is absent, HS
586	    // additionally consults the theory's in-file `configuration:` block
587	    // (`configStopOnTrace`, TheoryLoader.hs:640-666) — a PER-THEORY value,
588	    // so the effective strategy is resolved inside the file loop by
589	    // `effective_config` once the theory is parsed.
590	    // --output-json / --output-dot: trace graph serialisation isn't
591	    // ported yet (HS emits a graph of the attack-trace nodes/edges
592	    // for any falsified lemma — `outputTraces`, Batch.hs:251-271).  Don't
593	    // hard-error — many callers pass these flags unconditionally and just
594	    // want them harmless.  Write the exact bytes HS emits in the NO-TRACE
595	    // case so downstream tooling can `stat`/parse them; the trace-FOUND
596	    // case (real graphs) remains unported.  Print a one-line warning so the
597	    // user knows the contents aren't real.
598	    //
599	    // HS no-trace bytes (verified against the v1.13.0 binary):
600	    //   --output-dot:  `intercalate "\n" [] = ""`, then `writeFile ""`
601	    //                  ⇒ a 0-byte file (NOT "digraph trace {}").
602	    //   --output-json: `sequentsToJSONPretty graphOptions []`
603	    //                  (JSON.hs:458-463) = aeson-pretty `encodePretty`
604	    //                  of `{graphs:[]}` with the default Config
605	    //                  (confIndent = Spaces 4, confTrailingNewline = False)
606	    //                  ⇒ exactly `{\n    "graphs": []\n}` (20 bytes, NO
607	    //                  trailing newline; empty array renders inline).
608	    if let Some(p) = &args.trace_json {
609	        if !args.quiet {
610	            eprintln!("warning: --output-json: trace graph serialisation not yet ported; writing empty stub to {}", p);
611	        }
612	        fs::write(p, "{\n    \"graphs\": []\n}").map_err(|e| {
613	            RunError(format!("failed to write {}: {}", p, e))
614	        })?;
615	    }
616	    if let Some(p) = &args.trace_dot {
617	        if !args.quiet {
618	            eprintln!("warning: --output-dot: trace graph serialisation not yet ported; writing empty stub to {}", p);
619	        }
620	        fs::write(p, "").map_err(|e| {
621	            RunError(format!("failed to write {}: {}", p, e))
622	        })?;
623	    }
624	    if args.in_files.is_empty() {
625	        return Err(RunError(
626	            "no input files given\n\n".to_string() + crate::cli::adapt::help_text_default(),
627	        ));
628	    }
629	    let mut overall_status = 0i32;
630	    let mut file_results: Vec<FileResult> = Vec::new();
631	
632	    let parser_flags: Vec<&str> = args.defines.iter().map(String::as_str).collect();
633	
634	    // The Maude version is constant for the whole run, but detecting it
635	    // spawns a `maude --version` subprocess.  Detect it ONCE here and
636	    // reuse the cached value for both the banner and every file's
637	    // `BuildInfo`, avoiding one `maude --version` subprocess per file.
638	    let maude_version: Option<String> = crate::cli::detect_maude_version_pub();
639	
640	    // HS prints the maude tool + version banner ONCE at the top of the
641	    // batch run (`Main.Console.argExists` path).  Mirror that here:
642	    // emit `maude tool: 'maude'\n checking version: X. OK.\n checking
643	    // installation: OK.` before the first theory is loaded.  Suppressed
644	    // by `--quiet`.
645	    if !args.quiet && !args.parse_only {
646	        print_maude_banner(&maude_display_name(args), maude_version.as_deref());
647	    }
648	
649	    for in_file in &args.in_files {
650	        let t0 = Instant::now();
651	        let src = fs::read_to_string(in_file).map_err(|e| {
652	            RunError(format!("failed to read {}: {}", in_file, e))
653	        })?;
654	        // Thread the including file's directory so `#include "file"` resolves
655	        // relative to it (HS `takeDirectory inFile0`, Parser.hs:323-343).
656	        let base_dir = std::path::Path::new(in_file)
657	            .parent()
658	            .map(|p| p.to_path_buf());
659	        let mut parsed = match tamarin_parser::parse_theory_with_base(&src, &parser_flags, base_dir) {
660	            Ok(thy) => thy,
661	            Err(e) => {
662	                // HS batch: `handleError e@(ParserError _) = die $ show e`
663	                // (Main/Mode/Batch.hs:234).  `die` writes `show e` — the raw
664	                // parsec frame, with `inFile` as the `SourcePos` name — to
665	                // stderr and exits with code 1.  No `error:` prefix and no
666	                // `parse error in …:` wrapper (neither of which HS emits).
667	                eprintln!("{}", e.with_source(in_file.clone()));
668	                return Ok(1);
669	            }
670	        };
671	        // HS `liftedAddProtoRule` (Theory/Text/Parser.hs:166-193) runs per
672	        // rule DURING parsing: it expands each rule's `_restrict(φ)`
673	        // embedded restriction into a fresh `Restr_<rule>_<i>` restriction
674	        // (inserted before the rule) and rewrites the rule's actions to
675	        // reference it.  RS captures `_restrict` into
676	        // `Rule.embedded_restrictions` at parse time; run the equivalent
677	        // lifting pass here, BEFORE wellformedness / elaboration / rendering,
678	        // so the transformed parser theory drives all three (the renderer
679	        // iterates `parsed.items`).
680	        tamarin_theory::rule_restriction::lift_rule_restrictions(&mut parsed)
681	            .map_err(|e| RunError(format!(
682	                "_restrict expansion failed in {}: {}", in_file, e.message)))?;
683	        // HS emits this trace marker as soon as the theory parses
684	        // (TheoryLoader.hs:409).  `--parse-only` and `--quiet` skip it.
685	        let theory_name = parsed.name.clone();
686	        // HS `[Theory X] …` progress markers go to stderr and are suppressed
687	        // by `--quiet` / `--parse-only`.  Route all of them through one guard
688	        // so the suppression rule lives in a single place.
689	        let marker = |msg: &str| {
690	            if !args.quiet && !args.parse_only {
691	                eprintln!("[Theory {}] {}", theory_name, msg);
692	            }
693	        };
694	        marker("Theory loaded");
695	
696	        // Effective cut strategy + auto-sources for THIS theory: CLI flags
697	        // merged with the in-file `configuration:` block per HS
698	        // `closeTheory` (TheoryLoader.hs:640-666).
699	        let (cut, auto_sources) = effective_config(args, &parsed)?;
700	
701	        // Wellformedness checks — mirrors HS `checkWellformedness`
702	        // (`Theory.Tools.Wellformedness:1270`).  Runs on every file
703	        // (not gated by `--parse-only`) so a malformed theory is
704	        // surfaced even without proving.
705	        //
706	        // HS-faithful: HS's `thyProtoRules` (Wellformedness.hs:134)
707	        // applies `applyMacroInRule (theoryMacros thy)` to every rule
708	        // BEFORE the checks run — so `Fr(test())` where `test() = ~x`
709	        // becomes `Fr(~x)` and passes.  We mirror by cloning `parsed`
710	        // and expanding macros before handing it to `check_theory`.
711	        let parsed_for_wf = macro_expanded_clone(&parsed);
712	        let mut wf_report = tamarin_parser::wf::check_theory(&parsed_for_wf);
713	        // Strip the static "Message Derivation Checks" entry — the
714	        // dynamic check below replaces it with the prover-based result.
715	        // We keep the static check available for the `--parse-only`
716	        // path (where no Maude is started).
717	        if !args.parse_only {
718	            wf_report.retain(|e| e.topic != "Message Derivation Checks");
719	        }
720	        // HS `checkIfLemmasInTheory` (Wellformedness.hs:1156-1171) — FIRST
721	        // in HS's checkWellformedness list (line 1272).  Checks that every
722	        // --prove=X / --lemma=X name corresponds to a theory lemma.  This
723	        // check needs the CLI args (not embedded in the parser AST), so we
724	        // call it separately and PREPEND the result so it sorts first —
725	        // matching HS's `checkIfLemmasInTheory : ...` order.
726	        {
727	            let lemma_check = tamarin_parser::wf::check_if_lemmas_in_theory(
728	                &args.lemma_names, &parsed);
729	            if !lemma_check.is_empty() {
730	                let mut new_report = lemma_check;
731	                new_report.extend(wf_report);
732	                wf_report = new_report;
733	            }
734	        }
735	
736	        if args.parse_only {
737	            // HS-faithful: `--parse-only` does NOT run wellformedness
738	            // (checkWellformedness only fires inside `--prove`'s
739	            // close-theory pipeline).  Just re-emit the source verbatim.
740	            emit_output(args, in_file, &src)?;
741	            file_results.push(FileResult {
742	                in_file: in_file.clone(),
743	                out_file: out_path_for(args, in_file),
744	                results: Vec::new(),
745	                elapsed_ms: t0.elapsed().as_millis(),
746	                wf_count: 0,
747	            });
748	            continue;
749	        }
750	
751	        // Elaborate (mainly to get the protocol-specific MaudeSig).
752	        let mut elaborated = elaborate(&parsed).map_err(|e| {
753	            RunError(format!("elaboration error in {}: {}", in_file, e.message))
754	        })?;
755	        let maude_sig = elaborated.signature.maude_sig.clone();
756	
757	        // HS `checkEquationsSubtermConvergence` (Wellformedness.hs:1222-1232)
758	        // works on `thyEquations = S.toList (stRules sig)` — the SIGNATURE's
759	        // subterm-rule Set, not the parser-AST `equations:` blocks.  The
760	        // parser-level `check_theory` produced a placeholder entry from the AST
761	        // (source order, no width-wrap); replace it with the signature-driven,
762	        // HughesPJ-rendered version now that the `MaudeSig` is available.  This
763	        // mirrors HS exactly: `Ord CtxtStRule` Set order (e.g. f1, f2, f3, g
764	        // rather than source order f1, g, f2, f3) and `prettyCtxtStRule`'s
765	        // `sep [nest 2 lhs, "=" <-> rhs]` width-wrap for wide equations.
766	        // (Same retain/re-add pattern as the "Message Derivation Checks" swap.)
767	        wf_report.retain(|e| e.topic != "Subterm Convergence Warning");
768	        wf_report.extend(
769	            tamarin_theory::pretty_theory::subterm_convergence_report_wf(&maude_sig),

1440	            // failures, Maude crashes, IO errors) escalate to non-zero.
1441	            for r in &results {
1442	                if matches!(r.verdict, LemmaVerdict::Error(_)) {
1443	                    overall_status = overall_status.max(1);
1444	                }
1445	            }
1446	        }
1447	
1448	        // HS emits this marker after `closeTheory` finishes
1449	        // (TheoryLoader.hs:596).  In prove mode it is emitted before the
1450	        // prove loop (above); here it covers only the no-prove /
1451	        // precompute-only paths, which skip that loop.
1452	        if args.precompute_only || (!prove_anything && !any_stored_proof) {
1453	            marker("Theory closed");
1454	        }
1455	
1456	        // Build the HS-faithful theory pretty-print body.  This replaces
1457	        // the verbatim source dump with HS's `prettyClosedTheory`
1458	        // output shape — re-rendered signature, rules with `(modulo E)`
1459	        // prefix and AC-variant comments, lemmas with inline guarded
1460	        // formula and proof body, wellformedness block, and
1461	        // Generated-from footer.
1462	        //
1463	        // KNOWN GAP (--precompute-only): HS (Batch.hs:201-205) renders
1464	        // `ppWf report $--$ prettyPrecomputation thy''` here instead — a
1465	        // compact 3-line overview (`Multiset rewriting rules: N` / `Raw
1466	        // sources: …` / `Refined sources: …`, ClosedTheory.hs:548-570), NOT
1467	        // the full closed theory.  We fall through to pretty_closed_theory in
1468	        // that mode.  Porting `prettyPrecomputation` faithfully needs the
1469	        // closed theory's raw + refined source case lists and per-case
1470	        // `unsolvedChainConstraints` counts (which live in the prover
1471	        // session, not surfaced here); --precompute-only is a niche
1472	        // diagnostic mode not exercised by the example corpus.
1473	        let build_info = tamarin_theory::pretty_theory::BuildInfo {
1474	            tamarin_version: crate::cli::VERSION.to_string(),
1475	            maude_version: maude_version
1476	                .clone()
1477	                .unwrap_or_else(|| "unknown".to_string()),
1478	            git_revision: crate::cli::GIT_REV.to_string(),
1479	            git_branch: crate::cli::GIT_BRANCH.to_string(),
1480	            compiled_at: crate::cli::BUILD_TIMESTAMP.to_string(),
1481	        };
1482	        let wf_block = tamarin_theory::pretty_theory::format_wf_block(&wf_report);
1483	        let body = tamarin_theory::pretty_theory::pretty_closed_theory(
1484	            &parsed,
1485	            &elaborated,
1486	            &proved_lemmas,
1487	            &wf_block,
1488	            &build_info,
1489	            in_file,
1490	            auto_sources,
1491	        );
1492	        emit_output(args, in_file, &body)?;
1493	
1494	        file_results.push(FileResult {
1495	            in_file: in_file.clone(),
1496	            out_file: out_path_for(args, in_file),
1497	            results,
1498	            elapsed_ms: t0.elapsed().as_millis(),
1499	            wf_count: wf_report.len(),
1500	        });
1501	        if args.quit_on_warning && !wf_report.is_empty() {
1502	            return Err(RunError(format!(
1503	                "{} wellformedness check(s) failed (--quit-on-warning set)",
1504	                wf_report.len()
1505	            )));
1506	        }
1507	    }
1508	
1509	    // HS-faithful: `--parse-only` skips the `summary of summaries:`
1510	    // block entirely.  Only `--prove` (or any flag that actually runs
1511	    // the prover) emits it.
1512	    if !args.quiet && !args.parse_only {
1513	        print_overall_summary(&file_results, args.prove_mode);
1514	    }
1515	
1516	    Ok(overall_status)
1517	}
