1519	/// Install rayon's global worker pool to the size requested via
1520	/// `--processors=N` (or a sensible default).
1521	///
1522	/// HS-equivalent: GHC's `+RTS -N RTS_FLAG` sets the worker capacity for
1523	/// the `par*`/`Strategies` sites HS uses.  We mirror that surface via a
1524	/// CLI flag.  Idempotent across files in a batch — `build_global`
1525	/// silently errors on the second call, which is what we want.
1526	///
1527	/// Default: `available_parallelism()` (full machine).  `MaudePool`
1528	/// (`--maude-processes=M`) removes the Maude IPC mutex contention that
1529	/// would otherwise serialise every worker on a single subprocess, so
1530	/// users can productively scale to every core.  Memory budget is
1531	/// mediated by `--maude-processes`, which defaults to `processors` (1:1).
1532	fn init_rayon_pool(args: &Args) {
1533	    let n = args.effective_processors();
1534	    // `build_global` is idempotent-error: the SECOND call returns Err
1535	    // even if N matches.  We swallow the error: the first invocation
1536	    // wins (which is the desired behaviour — RS runs `run_batch` once
1537	    // per process, and tests install their own pool).
1538	    let _ = rayon::ThreadPoolBuilder::new()
1539	        .num_threads(n)
1540	        .thread_name(|i| format!("tamarin-rayon-{}", i))
1541	        .build_global();
1542	}
