1576	/// Resolve the output path for `in_file` given the user's `-o` / `-O`
1577	/// flags. Returns `None` when output should go to stdout.
1578	pub fn out_path_for(args: &Args, in_file: &str) -> Option<String> {
1579	    if let Some(of) = &args.output_file {
1580	        if !of.is_empty() {
1581	            return Some(of.clone());
1582	        }
1583	    }
1584	    if let Some(dir) = &args.output_dir {
1585	        let stem = std::path::Path::new(in_file)
1586	            .file_stem()
1587	            .and_then(|s| s.to_str())
1588	            .unwrap_or("theory");
1589	        let mut p = PathBuf::from(dir);
1590	        p.push(format!("{}_analyzed.spthy", stem));
1591	        return Some(p.to_string_lossy().to_string());
1592	    }
1593	    None
1594	}
