/// Map the driver's [`LemmaVerdict`] to the clean framing verdict enum. The
/// per-lemma phrase text (`verified` / `falsified - …` / `analysis incomplete` /
/// `analysis cannot be finished (reducible operators in subterms)`) lives entirely
/// in `framing::verdict_phrase`; this only classifies which of the four
/// batch-reachable verdicts a lemma landed in.
fn map_verdict(v: &LemmaVerdict) -> framing::LemmaResult {
    match v {
        LemmaVerdict::Verified => framing::LemmaResult::Verified,
        LemmaVerdict::Falsified => framing::LemmaResult::Falsified,
        // HS `UnfinishableProof` → `analysis cannot be finished (…)`.
        LemmaVerdict::Unfinishable => framing::LemmaResult::AnalysisCannotBeFinished,
        LemmaVerdict::Analyzed | LemmaVerdict::Skipped | LemmaVerdict::Filtered => {
            framing::LemmaResult::AnalysisIncomplete
        }
        // Batch-unreachable in the reference (console cluster round-7 negative
        // taxonomy, BEHAVIOR.md §15d): `UndeterminedProof`/`InvalidatedProof`
        // never fold out of a batch `--prove` (close-time replay annotates every
        // node → Incomplete; Invalidated only arises from interactive reuse-lemma
        // edits), and an RS-internal proving error surfaces via the escalated exit
        // code plus a runtime stderr line, never a per-lemma verdict phrase.
        // Collapse them to the incomplete phrase so the summary stays well-formed
        // without inventing a non-reference string.
        LemmaVerdict::Undetermined | LemmaVerdict::Invalidated | LemmaVerdict::Error(_) => {
            framing::LemmaResult::AnalysisIncomplete
        }
    }
}

