fn print_overall_summary(file_results: &[FileResult], prove_mode: bool) {
    // Route the `summary of summaries:` block through the vendored clean
    // `framing` module: map each `FileResult` to a clean `Summary` and let
    // `render_summary` assemble the `=`-ruled block. Its byte output equals what
    // the incremental `emit::BatchEmitter::finish` would flush — the driver
    // streams progress/payload as they are produced and buffers only this single
    // trailing block, exactly the emitter's contract.
    let summaries: Vec<framing::Summary> =
        file_results.iter().map(|fr| to_clean_summary(fr, prove_mode)).collect();
    print!("{}", framing::render_summary(&summaries));
}

/// Map one file's result into the clean framing [`framing::Summary`].
fn to_clean_summary(fr: &FileResult, prove_mode: bool) -> framing::Summary {
    framing::Summary {
        analyzed: fr.in_file.clone(),
        output: fr.out_file.clone(),
        processing_time: fr.elapsed_ms as f64 / 1000.0,
        // HS emits the `WARNING:` count line whenever a check failed, and the
        // `The analysis results might be wrong!` advisory only under `--prove`
        // (Batch.hs:246); the clean `WarningSummary` models both.
        warnings: (fr.wf_count > 0).then(|| framing::WarningSummary {
            failed_checks: fr.wf_count as u64,
            analysis_maybe_wrong: prove_mode,
        }),
        lemmas: fr.results.iter().map(to_clean_outcome).collect(),
    }
}

/// Map one lemma result into a clean whole-theory [`framing::LemmaOutcome`].
fn to_clean_outcome(r: &LemmaResult) -> framing::LemmaOutcome {
    let kind = if r.exists_trace {
        framing::TraceKind::ExistsTrace
    } else {
        framing::TraceKind::AllTraces
    };
    framing::LemmaOutcome::whole(r.name.clone(), kind, map_verdict(&r.verdict), r.proof_steps as u64)
}

